// Worker-level outcome constants — set by ExecuteBead() on the result.
// The parent orchestrator (LandBeadResult + ApplyLandingToResult) then
// overwrites Outcome and Status with the landing decision.
const (
	ExecuteBeadOutcomeTaskSucceeded  = "task_succeeded"
	ExecuteBeadOutcomeTaskFailed     = "task_failed"
	ExecuteBeadOutcomeTaskNoChanges  = "task_no_changes"
	ExecuteBeadOutcomeTaskNoEvidence = "task_no_evidence"
)

// Status constants — used by the loop and other consumers of ExecuteBeadReport.
// These map to specific close/unclaim behaviors in ExecuteBeadWorker.
const (
	ExecuteBeadStatusStructuralValidationFailed = "structural_validation_failed"
	ExecuteBeadStatusExecutionFailed            = "execution_failed"
	ExecuteBeadStatusPostRunCheckFailed         = "post_run_check_failed"
	ExecuteBeadStatusRatchetFailed              = "ratchet_failed"
	ExecuteBeadStatusLandConflict               = "land_conflict"
	ExecuteBeadStatusPushFailed                 = "push_failed"
	ExecuteBeadStatusPushConflict               = "push_conflict"
	ExecuteBeadStatusPreservedNeedsReview       = "preserved_needs_review"
	ExecuteBeadStatusNoEvidenceProduced         = "no_evidence_produced"
	ExecuteBeadStatusNoChanges                  = "no_changes"
	ExecuteBeadStatusAlreadySatisfied           = "already_satisfied"
	ExecuteBeadStatusSuccess                    = "success"
	ExecuteBeadStatusResourceExhausted          = "resource_exhausted"

	// ExecuteBeadStatusDeclinedNeedsDecomposition is a structured outcome
	// signalling that the executor inspected the bead and concluded it cannot
	// be delivered in a single pass — typically because the scope is
	// epic-sized and must first be broken into sub-beads. It is distinct
	// from no_changes (which means "I tried and there was nothing to change")
	// and from execution_failed (which means the agent or harness errored).
	//
	// The loop treats this status as terminal-for-loop: it parks the bead
	// with a long cooldown and records the recommended sub-beads as a
	// structured `decomposition-recommendation` event. No further attempts
	// happen until an operator clears the cooldown (e.g. via
	// `ddx bead cooldown clear`) or splits the bead.
	ExecuteBeadStatusDeclinedNeedsDecomposition = "declined_needs_decomposition"

	// Post-merge review outcomes. The bead was merged, then reviewed;
	// the review returned a non-APPROVE verdict and the bead was reopened.
	ExecuteBeadStatusReviewRequestChanges = "review_request_changes"
	ExecuteBeadStatusReviewBlock          = "review_block"
	ExecuteBeadStatusReviewMalfunction    = "review_malfunction"

	// ExecuteBeadStatusReviewRequestClarification is set when the reviewer
	// returns REQUEST_CLARIFICATION — it cannot adjudicate one or more
	// needs-judgment AC items without operator input. The bead moves to
	// status=proposed (operator lane) without blocking the drain queue.
	ExecuteBeadStatusReviewRequestClarification = "review_request_clarification"

	// ExecuteBeadStatusLandConflictUnresolvable is set when work
	// attempted 3-way ort auto-resolution and (if configured) a focused
	// conflict-resolve agent run for a preserved iteration, and both failed.
	// The bead is parked under LandConflictCooldown for operator review.
	ExecuteBeadStatusLandConflictUnresolvable = "land_conflict_unresolvable"

	// ExecuteBeadStatusLandConflictOperatorRequired is set when the focused
	// conflict-resolve agent escalated to BLOCKING — the conflict requires
	// operator judgment, not automated retry. The bead moves to status=proposed
	// with a kind:land-conflict-operator-required event.
	ExecuteBeadStatusLandConflictOperatorRequired = "land_conflict_operator_required"

	// ExecuteBeadStatusReviewTerminalBlock is set when a BLOCK review verdict
	// is classified as a terminal operator-required condition —
	// review_spec_gap, review_missing_acceptance, review_too_large at depth
	// cap, or review_unsafe_or_out_of_scope. These classes do not re-enter
	// the automated retry cycle and do not consume the no-progress retry
	// budget; the bead moves to status=proposed until an operator
	// intervenes.
	ExecuteBeadStatusReviewTerminalBlock = "review_terminal_block"

	// ExecuteBeadStatusReviewFixableGap is set when a BLOCK review verdict is
	// classified as a fixable gap — the issues are addressable by a repair
	// attempt at higher MinPower with the reviewer's rationale as context.
	// Exactly one repair cycle is scheduled per result_rev; a second
	// review_fixable_gap on the same result_rev falls through to the regular
	// BLOCK triage path instead.
	ExecuteBeadStatusReviewFixableGap = "review_fixable_gap"

	// ExecuteBeadStatusRepairCycleExhausted is set when the candidate-cycle
	// repair loop reaches its per-attempt repair_max_cycles limit before a
	// reviewer approves the candidate. The latest candidate ref is retained for
	// operator inspection.
	ExecuteBeadStatusRepairCycleExhausted = "repair-cycle-exhausted"
)

// ClassifyExecuteBeadStatus maps a landing outcome to the supervisor-visible
// status contract. This is called by ApplyLandingToResult and by callers who
// build an ExecuteBeadReport from a landing result.
func ClassifyExecuteBeadStatus(outcome string, exitCode int, reason string) string {
	if exitCode != 0 {
		return ExecuteBeadStatusExecutionFailed
	}

	switch outcome {
	case "merged":
		// A merged outcome whose reason carries the push-failure marker
		// means the local target branch advanced but `git push` rejected the
		// new tip (large blob, branch protection, auth, divergence, etc.).
		// Classify these as push_failed so the loop refuses to close the
		// bead and operators are forced to investigate.
		if strings.HasPrefix(reason, PushConflictReasonPrefix) {
			return ExecuteBeadStatusPushConflict
		}
		if strings.HasPrefix(reason, PushFailedReasonPrefix) {
			return ExecuteBeadStatusPushFailed
		}
		return ExecuteBeadStatusSuccess
	case "no-changes", ExecuteBeadOutcomeTaskNoChanges:
		return ExecuteBeadStatusNoChanges
	case "no-evidence", ExecuteBeadOutcomeTaskNoEvidence:
		return ExecuteBeadStatusNoEvidenceProduced
	case "error":
		return ExecuteBeadStatusExecutionFailed
	case "preserved":
		switch {
		case reason == "merge conflict" || reason == "merge failed" || reason == "ff-merge not possible":
			return ExecuteBeadStatusLandConflict
		case reason == "post-run checks failed", strings.HasPrefix(reason, PreMergeChecksReason):
			return ExecuteBeadStatusPostRunCheckFailed
		case reason == RatchetPreserveReason:
			return ExecuteBeadStatusRatchetFailed
		case reason == AttemptIntegrityPreserveReason:
			return ExecuteBeadStatusPreservedNeedsReview
		case reason == OperatorCancelReason:
			return ExecuteBeadStatusPreservedNeedsReview
		}
		if isPreservedNeedsReviewReason(reason) {
			return ExecuteBeadStatusPreservedNeedsReview
		}
		// Preserved iterations may still be success when the caller
		// explicitly requested no merge.
		return ExecuteBeadStatusSuccess
	case ExecuteBeadOutcomeTaskSucceeded:
		return ExecuteBeadStatusSuccess
	case ExecuteBeadOutcomeTaskFailed:
		return ExecuteBeadStatusExecutionFailed
	default:
		return ExecuteBeadStatusExecutionFailed
	}
}

// IsResourceExhaustedStatus reports whether the status is the stable
// host-resource failure classification.
func IsResourceExhaustedStatus(status string) bool {
	return status == ExecuteBeadStatusResourceExhausted
}

func isPreservedNeedsReviewReason(reason string) bool {
	for _, prefix := range []string{
		"evidence commit failed:",
		"large-deletion gate:",
		"syntax sanity gate:",
		"post-land gate failed:",
	} {
		if strings.HasPrefix(reason, prefix) {
			return true
		}
	}
	return false
}

func ExecuteBeadStatusDetail(status, reason, errMsg string) string {
	switch {
	case reason != "" && errMsg != "" && reason != errMsg:
		return reason + ": " + errMsg
	case reason != "":
		return reason
	case errMsg != "":
		return errMsg
	case status != "":
		return status
	default:
		return "unknown"
	}
}

package agent

import (
	"context"
	"time"

	agenttry "github.com/DocumentDrivenDX/ddx/internal/agent/try"
	"github.com/DocumentDrivenDX/ddx/internal/agent/work"
)

type loopPhaseEmitter struct {
	progressCh chan<- ProgressEvent
	emit       func(string, map[string]any)
	workerID   string
	projectID  string
	harness    string
	model      string
	profile    string
	runStart   time.Time
	now        func() time.Time
	phaseSeq   *int
}

func newLoopPhaseEmitter(runtime ExecuteBeadLoopRuntime, harness, model, profile string, runStart time.Time, now func() time.Time, phaseSeq *int, emit func(string, map[string]any)) *loopPhaseEmitter {
	if now == nil {
		now = time.Now
	}
	return &loopPhaseEmitter{
		progressCh: runtime.ProgressCh,
		emit:       emit,
		workerID:   runtime.WorkerID,
		projectID:  runtime.ProjectRoot,
		harness:    harness,
		model:      model,
		profile:    profile,
		runStart:   runStart,
		now:        now,
		phaseSeq:   phaseSeq,
	}
}

func (e *loopPhaseEmitter) EmitProgress(_ context.Context, beadID string, phase work.Phase, outcome work.Outcome) error {
	if e == nil {
		return nil
	}
	phaseSeq := e.nextPhaseSeq()
	progressPhase := string(phase)
	if phase == work.PhaseTerminal {
		progressPhase = terminalProgressPhase(outcome)
	}
	evt := newProgressEvent(
		e.workerID,
		e.projectID,
		beadID,
		outcome.AttemptID,
		e.harness,
		e.model,
		e.profile,
		progressPhase,
		phaseSeq,
		false,
		e.now().Sub(e.runStart).Milliseconds(),
	)
	evt.TS = e.now().UTC()
	evt.Message = outcome.Detail
	emitProgress(e.progressCh, evt)
	return nil
}

func (e *loopPhaseEmitter) EmitResult(_ context.Context, beadID string, outcome work.Outcome) error {
	if e == nil || e.emit == nil {
		return nil
	}
	durationMS := outcome.DurationMS
	if durationMS == 0 {
		durationMS = e.now().Sub(e.runStart).Milliseconds()
	}
	e.emit("bead.result", map[string]any{
		"bead_id":              beadID,
		"status":               outcome.Status,
		"detail":               outcome.Detail,
		"session_id":           outcome.SessionID,
		"result_rev":           outcome.ResultRev,
		"base_rev":             outcome.BaseRev,
		"preserve_ref":         outcome.PreserveRef,
		"no_changes_rationale": outcome.NoChangesRationale,
		"duration_ms":          durationMS,
	})
	return nil
}

func (e *loopPhaseEmitter) nextPhaseSeq() int {
	if e == nil || e.phaseSeq == nil {
		return 0
	}
	*e.phaseSeq = *e.phaseSeq + 1
	return *e.phaseSeq
}

func terminalProgressPhase(outcome work.Outcome) string {
	switch outcome.Status {
	case ExecuteBeadStatusSuccess, ExecuteBeadStatusAlreadySatisfied:
		return "done"
	default:
		if outcome.PreserveRef != "" {
			return "preserved"
		}
		return "failed"
	}
}

func phaseOutcomeFromReport(report ExecuteBeadReport, attemptID string, durationMS int64) work.Outcome {
	return work.Outcome{
		AttemptID:          attemptID,
		Status:             report.Status,
		Detail:             report.Detail,
		SessionID:          report.SessionID,
		ResultRev:          report.ResultRev,
		BaseRev:            report.BaseRev,
		PreserveRef:        report.PreserveRef,
		NoChangesRationale: report.NoChangesRationale,
		DurationMS:         durationMS,
	}
}

func phaseOutcomeFromAttemptOut(report ExecuteBeadReport, attemptOut agenttry.Outcome, attemptID string, durationMS int64) work.Outcome {
	outcome := phaseOutcomeFromReport(report, attemptID, durationMS)
	outcome.Disposition = string(attemptOut.Disposition)
	if attemptOut.Parking != nil && attemptOut.Parking.Event != nil {
		outcome.ParkReason = attemptOut.Parking.Event.Kind
	}
	return outcome
}

func formatLoopResult(report ExecuteBeadReport) string {
	switch report.Status {
	case ExecuteBeadStatusSuccess:
		shortRev := report.ResultRev
		if len(shortRev) > 8 {
			shortRev = shortRev[:8]
		}
		if shortRev != "" {
			return fmt.Sprintf("merged (%s)", shortRev)
		}
		return "merged"
	case ExecuteBeadStatusAlreadySatisfied:
		return "already_satisfied"
	case ExecuteBeadStatusResourceExhausted:
		if report.Detail != "" {
			return fmt.Sprintf("resource_exhausted: %s", report.Detail)
		}
		return "resource_exhausted"
	case ExecuteBeadStatusNoChanges:
		if report.NoChangesRationale != "" {
			return fmt.Sprintf("no_changes: %s", report.NoChangesRationale)
		}
		return "no_changes"
	case ExecuteBeadStatusNoEvidenceProduced:
		detail := report.Detail
		if detail == "" {
			detail = "agent exited without a commit or no_changes_rationale.txt"
		}
		return fmt.Sprintf("no_evidence_produced: %s", detail)
	default:
		detail := report.Detail
		if detail == "" {
			detail = report.Status
		}
		if report.OutcomeReason != "" {
			return fmt.Sprintf("%s: %s", report.OutcomeReason, detail)
		}
		if report.PreserveRef != "" {
			return fmt.Sprintf("preserved: %s", detail)
		}
		return fmt.Sprintf("error: %s", detail)
	}
}

func formatLoopResultLine(beadID string, report ExecuteBeadReport) string {
	return fmt.Sprintf("%s %s → %s", loopResultMarker(report), beadID, formatLoopResult(report))
}

func loopResultMarker(report ExecuteBeadReport) string {
	switch report.Status {
	case ExecuteBeadStatusSuccess, ExecuteBeadStatusAlreadySatisfied:
		return "✓"
	case ExecuteBeadStatusNoChanges, ExecuteBeadStatusResourceExhausted:
		return "•"
	default:
		return "✗"
	}
}

func classifyLoopReportFailure(report *ExecuteBeadReport) {
	if report == nil || report.Status == ExecuteBeadStatusSuccess || report.Status == ExecuteBeadStatusAlreadySatisfied {
		return
	}
	if report.OutcomeReason != "" {
		return
	}
	combined := strings.TrimSpace(strings.Join([]string{
		report.Detail,
		report.Error,
		report.Stderr,
	}, "\n"))

}

func writeTryResult(w io.Writer, report agent.ExecuteBeadReport) {
	fmt.Fprintf(w, "\nbead: %s\nstatus: %s\n", report.BeadID, report.Status)
	if report.Detail != "" {
		fmt.Fprintf(w, "detail: %s\n", report.Detail)
	}
	if report.ResultRev != "" {
		fmt.Fprintf(w, "result_rev: %s\n", report.ResultRev)
	}
	if report.ImplementationRev != "" && report.ImplementationRev != report.LandedRev {
		fmt.Fprintf(w, "implementation_rev: %s\n", report.ImplementationRev)
	}
	if report.LandedRev != "" && report.LandedRev != report.ImplementationRev {
		fmt.Fprintf(w, "landed_rev: %s\n", report.LandedRev)
	}
	if isSuccessfulTryResult(report) && report.TargetBranch != "" {
		fmt.Fprintf(w, "landed_branch: %s\n", report.TargetBranch)
	}
	if isSuccessfulTryResult(report) && report.ProjectRoot != "" {
		fmt.Fprintf(w, "project_root: %s\n", report.ProjectRoot)
	}
	if report.PreserveRef != "" {
		fmt.Fprintf(w, "preserve_ref: %s\n", report.PreserveRef)
	}
	if needsNoRewriteLandingRescue(report) {
		fmt.Fprintf(w, "landing_scope: branch-local\n")
		fmt.Fprintf(w, "rescue_command: %s\n", noRewriteLandingRescueCommand(report.TargetBranch))
		fmt.Fprintf(w, "dirty_worktree_rescue: %s\n", dirtyWorktreeRescueCommand(report.TargetBranch))
	}
}

func isSuccessfulTryResult(report agent.ExecuteBeadReport) bool {
	return report.Status == agent.ExecuteBeadStatusSuccess || report.Status == agent.ExecuteBeadStatusAlreadySatisfied
}

func needsNoRewriteLandingRescue(report agent.ExecuteBeadReport) bool {
	if !isSuccessfulTryResult(report) || report.TargetBranch == "" {
		return false
	}
	switch report.TargetBranch {
	case "main", "master", "trunk":
		return false
	default:
		return true
	}
}

func noRewriteLandingRescueCommand(branch string) string {
	return "git merge --no-ff " + branch
}

func dirtyWorktreeRescueCommand(branch string) string {
	safeBranch := strings.NewReplacer("/", "-", "\\", "-", " ", "-").Replace(branch)
	return fmt.Sprintf("git worktree add ../ddx-rescue-%s <target-branch> && cd ../ddx-rescue-%s && git merge --no-ff %s", safeBranch, safeBranch, branch)
}

// tryExitCodeForStatus maps a bead execution status string to the ddx try exit code contract.
func tryExitCodeForStatus(status string) error {
	switch status {
	case agent.ExecuteBeadStatusSuccess, agent.ExecuteBeadStatusAlreadySatisfied:
		return nil // exit 0
	case agent.ExecuteBeadStatusPreservedNeedsReview, agent.ExecuteBeadStatusNoChanges,
		agent.ExecuteBeadStatusNoEvidenceProduced:
		return &ExitError{Code: tryExitPreservedOrNone, Message: ""}
	default:
		// execution_failed and all other terminal non-success statuses
		return &ExitError{Code: tryExitFailed, Message: ""}
	}
}

// unmetDeps returns the IDs of deps that are not yet closed, in the order
// they appear in the bead's dependency list.
func unmetDeps(store *bead.Store, b *bead.Bead) []string {
	depIDs := b.DepIDs()
	if len(depIDs) == 0 {
		return nil
	}
	var unmet []string
	for _, depID := range depIDs {
		dep, err := store.Get(context.Background(), depID)
		if err != nil || dep.Status != bead.StatusClosed {
			unmet = append(unmet, depID)
		}
	}
	return unmet
}

